/** Call-by-value, Call-by-name, and Call-by-need Jam interpreter */

import java.io.IOException;
import java.io.Reader;

/** Interpreter Classes */

/** A class that implements call-by-value, call-by-name, and call-by-need interpretation of Jam programs. */
class Interpreter {

  /** program for this interpreter, initialized in constructors. */
  AST prog;

  /** Constructor for a program given in a file. */
  public Interpreter(String fileName) throws IOException {
    Parser p = new Parser(fileName);
    prog = p.parse();
  }

  /** Constructor for a program already embedded in a Parser object. */
  public Interpreter(Parser p) {
    prog = p.parse();
  }

  /** Constructor for a program embedded in a Reader. */
  public Interpreter(Reader reader) {
    Parser p = new Parser(reader);
    prog = p.parse();
  }

  /** Parses and CBV interprets the input embedded in parser */
  public JamVal callByValue() { return prog.accept(valueEvalVisitor); }

  /** Parses and CBNm interprets the input embedded in parser */
  public JamVal callByName() { return prog.accept(nameEvalVisitor); }

  /** Parses and CBNd interprets the input embedded in parser */
  public JamVal callByNeed() { return prog.accept(needEvalVisitor); }

  /** A class representing an unevaluated expression (together with the corresponding evaluator). */
  private static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;

    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }

    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }

    /** Evaluates this suspension. */
    public JamVal eval() {
      return exp.accept(ev);
    }

    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** Class representing a binding in CBV evaluation. */
  private static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    /** Returns the already-computed value. */
    public JamVal value() { return value; }
    /** Sets the binding value by evaluating the suspension. */
    public void setBinding(Suspension s) { value = s.eval(); }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
  private static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) {
      super(v, null);
      susp = s;
    }
    /** Evaluates the suspension each time the value is requested. */
    public JamVal value() { return susp.eval(); }
    /** Replaces the suspension with a new one. */
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** Class representing a binding in CBNeed evaluation.  The inherited value field is used to hold the value
    * first computed by need-driven evaluation. */
  private static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v,s); }
    /** Evaluates the suspension on first access, then caches and returns the cached value. */
    public JamVal value() {
      if (value == null) {
        value = susp.eval();
      }
      return value;
    }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  /** Visitor class implementing a lookup method on environments.
    * @return value() for variable var for both lazy and eager environments. */
  private static class LookupVisitor implements PureListVisitor<Binding,JamVal> {

    Variable var;   // the lexer guarantees that there is only one Variable for a given name

    LookupVisitor(Variable v) { var = v; }

    /** Variable not found in the environment. */
    public JamVal forEmpty(Empty<Binding> e) {
      throw new EvalException("Variable " + var + " is not bound");
    }
    /** Check if the first binding matches; if not, search the rest. */
    public JamVal forCons(Cons<Binding> c) {
      Binding b = c.first();
      if (b.var() == var) return b.value();
      return c.rest().accept(this);
    }
  }

  /** The interface supporting various evaluation policies (CBV, CBNm, CBNd) for map applications and let constructions. */
  private interface EvalPolicy {
    /** Constructs the appropriate binding object for this, binding var to ast in the evaluator ev */
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
  }

  /** An ASTVisitor class for evaluating ASTs where the evaluation policy for function applications and other
    * binding operations such as let are determined by an embedded EvalPolicy. */
  private static class EvalVisitor implements ASTVisitor<JamVal> {

    /* The code in this class assumes that:
     * * OpTokens are unique;
     * * Variable objects are unique: v1.name.equals(v.name) => v1 == v2; and
     * * The only objects used as boolean values are BoolConstant.TRUE and BoolConstant.FALSE.
     * Hence,  == can be used to compare Variable objects, OpTokens, and BoolConstants. */

    private PureList<Binding> env;  // the embedded environment
    private EvalPolicy evalPolicy;  // the embedded EvalPolicy

    /** Constructor for recursive calls. */
    private EvalVisitor(PureList<Binding> e, EvalPolicy ep) {
      env = e;
      evalPolicy = ep;
    }

    /** Top level constructor. */
    public EvalVisitor(EvalPolicy ep) { this(new Empty<Binding>(), ep); }

    /** Factory method that constructs a new visitor with environment e and same evalPolicy as this. */
    public EvalVisitor newVisitor(PureList<Binding> e) {
      return new EvalVisitor(e, evalPolicy);
    }

    /** Factory method that constructs a Binding of var to ast corresponding to this.evalPolicy */
    public Binding newBinding(Variable var, AST ast) {
      return evalPolicy.newBinding(var, ast, this);
    }

    /** Getter for env field */
    public PureList<Binding> env() { return env; }

    /* ASTVisitor methods */

    /** Boolean constants evaluate to themselves. */
    public JamVal forBoolConstant(BoolConstant b) { return b; }

    /** Integer constants evaluate to themselves. */
    public JamVal forIntConstant(IntConstant i) { return i; }

    /** The empty constant evaluates to the JamEmpty singleton. */
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    /** Look up the variable in the current environment. */
    public JamVal forVariable(Variable v) {
      return env.accept(new LookupVisitor(v));
    }

    /** Primitive functions evaluate to themselves (they are JamVals). */
    public JamVal forPrimFun(PrimFun f) { return f; }

    /** Evaluate a unary operator application by evaluating the argument and dispatching on the operator. */
    public JamVal forUnOpApp(UnOpApp u) {
      JamVal val = u.arg().accept(this);
      return u.rator().accept(new StandardUnOpVisitor(val));
    }

    /** Evaluate a binary operator application by dispatching on the operator with unevaluated args. */
    public JamVal forBinOpApp(BinOpApp b) {
      return b.rator().accept(new StandardBinOpVisitor(b.arg1(), b.arg2(), this));
    }

    /** Evaluate a function application by evaluating the rator and applying it to the args. */
    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (!(rator instanceof JamFun))
        throw new EvalException(rator + " is not a function");
      return ((JamFun) rator).accept(new StandardFunVisitor(a.args(), this));
    }

    /** A map expression evaluates to a closure capturing the current environment. */
    public JamVal forMap(Map m) {
      return new JamClosure(m, env);
    }

    /** Evaluate if-then-else: evaluate the test, then evaluate one branch. */
    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant))
        throw new EvalException("Test of if is not a boolean");
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      return i.alt().accept(this);
    }

    /** Evaluate let by creating bindings (using current env) and evaluating body in extended env.
      * Non-recursive: all RHS expressions are associated with the original environment. */
    public JamVal forLet(Let l) {
      Def[] defs = l.defs();
      PureList<Binding> newEnv = env;
      for (int i = 0; i < defs.length; i++) {
        newEnv = newEnv.cons(newBinding(defs[i].lhs(), defs[i].rhs()));
      }
      return l.body().accept(newVisitor(newEnv));
    }
  }

  /** Top-level EvalVisitors implementing CBV, CBNm, and CBNd evaluation. */
  private static EvalVisitor valueEvalVisitor = new EvalVisitor(CallByValue.ONLY);
  private static EvalVisitor nameEvalVisitor = new EvalVisitor(CallByName.ONLY);
  private static EvalVisitor needEvalVisitor = new EvalVisitor(CallByNeed.ONLY);

  /** JamFunVisitor class that evaluates the application of a JamFun (the host) to the argument expressions given in
    * AST[] args using the given evalVisitor, which interprets ASTs. */
  private static class StandardFunVisitor implements JamFunVisitor<JamVal> {

    /** Unevaluated arguments */
    AST[] args;

    /** Evaluation visitor */
    EvalVisitor evalVisitor;

    StandardFunVisitor(AST[] asts, EvalVisitor ev) {
      args = asts;
      evalVisitor = ev;
    }

    /** Evaluate all arguments eagerly (used for primitive functions). */
    private JamVal[] evalArgs() {
      JamVal[] vals = new JamVal[args.length];
      for (int i = 0; i < args.length; i++) {
        vals[i] = args[i].accept(evalVisitor);
      }
      return vals;
    }

    /** Apply a closure: check arity, create bindings per evalPolicy, evaluate body in closure's extended env. */
    public JamVal forJamClosure(JamClosure closure) {
      Variable[] params = closure.code().vars();
      if (params.length != args.length)
        throw new EvalException("Closure " + closure.code() + " applied to " + args.length +
          " arguments, expected " + params.length);
      PureList<Binding> newEnv = closure.env();
      for (int i = 0; i < params.length; i++) {
        newEnv = newEnv.cons(evalVisitor.newBinding(params[i], args[i]));
      }
      return closure.code().body().accept(evalVisitor.newVisitor(newEnv));
    }

    /** Apply a primitive function: always evaluate args eagerly. */
    public JamVal forPrimFun(PrimFun primFun) {
      JamVal[] vals = evalArgs();
      return primFun.accept(new StandardPrimFunVisitor(vals));
    }
  }

  /** CBV: evaluate the argument and bind the variable to the resulting value. */
  private static class CallByValue implements EvalPolicy {

    public static final EvalPolicy ONLY = new CallByValue();
    private CallByValue() { }

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new ValueBinding(var, arg.accept(ev));
    }
  }

  /** CBN: bind the variable to a suspension of the argument expression. */
  private static class CallByName implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByName();
    private CallByName() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NameBinding(var, new ConcreteSuspension(arg, ev));
    }
  }

  /** CBNd: bind the variable to a need-suspension that caches its result on first evaluation. */
  private static class CallByNeed implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByNeed();
    private CallByNeed() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
  }

  /** Visitor for unary operators. Only supports eager (strict) unary operators. */
  private static class StandardUnOpVisitor implements UnOpVisitor<JamVal> {
    private final JamVal val;
    StandardUnOpVisitor(JamVal jv) { val = jv; }

    /** Returns val provided it is an IntConstant; throws EvalException otherwise. */
    private IntConstant checkInteger(String op) {
      if (!(val instanceof IntConstant))
        throw new EvalException("Unary operator `" + op + "' applied to non-integer " + val);
      return (IntConstant) val;
    }

    /** Returns val provided it is a BoolConstant; throws EvalException otherwise. */
    private BoolConstant checkBoolean(String op) {
      if (!(val instanceof BoolConstant))
        throw new EvalException("Unary operator `" + op + "' applied to non-boolean " + val);
      return (BoolConstant) val;
    }

    /** Unary +: identity on integers. */
    public JamVal forUnOpPlus() { return checkInteger("+"); }

    /** Unary -: negate an integer. */
    public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }

    /** Tilde: boolean negation. */
    public JamVal forOpTilde() { return checkBoolean("~").not(); }
  }

  /** Visitor for binary operators. Takes unevaluated AST args to support short-circuit evaluation of & and |. */
  private static class StandardBinOpVisitor implements BinOpVisitor<JamVal> {
    private AST arg1, arg2;
    private EvalVisitor evalVisitor;

    StandardBinOpVisitor(AST a1, AST a2, EvalVisitor ev) { arg1 = a1; arg2 = a2; evalVisitor = ev; }

    /** Evaluate the specified argument AST and confirm that it is an IntConstant. */
    private IntConstant evalIntegerArg(AST arg, String op) {
      JamVal v = arg.accept(evalVisitor);
      if (!(v instanceof IntConstant))
        throw new EvalException("Binary operator `" + op + "' applied to non-integer " + v);
      return (IntConstant) v;
    }

    /** Evaluate the specified argument AST and confirm that it is a BoolConstant. */
    private BoolConstant evalBooleanArg(AST arg, String op) {
      JamVal v = arg.accept(evalVisitor);
      if (!(v instanceof BoolConstant))
        throw new EvalException("Binary operator `" + op + "' applied to non-boolean " + v);
      return (BoolConstant) v;
    }

    /** Integer addition. */
    public JamVal forBinOpPlus() {
      return new IntConstant(evalIntegerArg(arg1, "+").value() + evalIntegerArg(arg2, "+").value());
    }

    /** Integer subtraction. */
    public JamVal forBinOpMinus() {
      return new IntConstant(evalIntegerArg(arg1, "-").value() - evalIntegerArg(arg2, "-").value());
    }

    /** Integer multiplication. */
    public JamVal forOpTimes() {
      return new IntConstant(evalIntegerArg(arg1, "*").value() * evalIntegerArg(arg2, "*").value());
    }

    /** Integer division (truncating toward zero). */
    public JamVal forOpDivide() {
      IntConstant v1 = evalIntegerArg(arg1, "/");
      IntConstant v2 = evalIntegerArg(arg2, "/");
      if (v2.value() == 0)
        throw new EvalException("Division by zero");
      return new IntConstant(v1.value() / v2.value());
    }

    /** Structural equality (identity for closures). */
    public JamVal forOpEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(v1.equals(v2));
    }

    /** Structural inequality. */
    public JamVal forOpNotEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(!v1.equals(v2));
    }

    /** Less than (integers only). */
    public JamVal forOpLessThan() {
      return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<").value() < evalIntegerArg(arg2, "<").value());
    }

    /** Greater than (integers only). */
    public JamVal forOpGreaterThan() {
      return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">").value() > evalIntegerArg(arg2, ">").value());
    }

    /** Less than or equals (integers only). */
    public JamVal forOpLessThanEquals() {
      return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<=").value() <= evalIntegerArg(arg2, "<=").value());
    }

    /** Greater than or equals (integers only). */
    public JamVal forOpGreaterThanEquals() {
      return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">=").value() >= evalIntegerArg(arg2, ">=").value());
    }

    /** Short-circuit and: returns false if first arg is false, otherwise evaluates and returns second arg. */
    public JamVal forOpAnd() {
      BoolConstant v1 = evalBooleanArg(arg1, "&");
      if (v1 == BoolConstant.FALSE) return BoolConstant.FALSE;
      return evalBooleanArg(arg2, "&");
    }

    /** Short-circuit or: returns true if first arg is true, otherwise evaluates and returns second arg. */
    public JamVal forOpOr() {
      BoolConstant v1 = evalBooleanArg(arg1, "|");
      if (v1 == BoolConstant.TRUE) return BoolConstant.TRUE;
      return evalBooleanArg(arg2, "|");
    }
  }

  /** Visitor that implements each primitive function. Primitives are always strict (args pre-evaluated). */
  private static class StandardPrimFunVisitor implements PrimFunVisitor<JamVal> {

    JamVal[] vals;  // evaluated arguments for PrimFun App

    StandardPrimFunVisitor(JamVal[] vls) { vals = vls; }

    /** Throws an arity error for the named primitive function. */
    private JamVal primFunError(String fn) {
      throw new EvalException("Primitive function `" + fn + "' applied to " + vals.length + " arguments");
    }

    /** Confirms that vals[0] is a JamCons (non-empty list). Assumes unary function. */
    private JamCons confirmJamCons(String funName) {
      if (vals.length != 1) primFunError(funName);
      if (!(vals[0] instanceof JamCons))
        throw new EvalException("`" + funName + "' applied to " + vals[0] + " which is not a non-empty list");
      return (JamCons) vals[0];
    }

    /** function?(p): returns true if p is a function (closure or primitive). */
    public JamVal forFunctionPPrim() {
      if (vals.length != 1) return primFunError("function?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
    }

    /** number?(p): returns true if p is an integer. */
    public JamVal forNumberPPrim() {
      if (vals.length != 1) return primFunError("number?");
      return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
    }

    /** list?(p): returns true if p is a list (JamEmpty or JamCons). */
    public JamVal forListPPrim() {
      if (vals.length != 1) return primFunError("list?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
    }

    /** cons?(p): returns true if p was created by cons. */
    public JamVal forConsPPrim() {
      if (vals.length != 1) return primFunError("cons?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
    }

    /** empty?(p): returns true if p is the empty list. */
    public JamVal forEmptyPPrim() {
      if (vals.length != 1) return primFunError("empty?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
    }

    /** cons(p,q): prepend p to list q. Error if q is not a list. */
    public JamVal forConsPrim() {
      if (vals.length != 2) return primFunError("cons");
      if (!(vals[1] instanceof JamList))
        throw new EvalException("`cons' applied with non-list second argument " + vals[1]);
      return new JamCons(vals[0], (JamList) vals[1]);
    }

    /** arity(p): returns the number of parameters of function p. Error if p is not a function. */
    public JamVal forArityPrim() {
      if (vals.length != 1) return primFunError("arity");
      JamVal v = vals[0];
      if (v instanceof JamClosure) {
        return new IntConstant(((JamClosure) v).code().vars().length);
      }
      if (v instanceof PrimFun) {
        // cons takes 2 arguments; all other primitives take 1
        if (v == ConsPrim.ONLY) return new IntConstant(2);
        return new IntConstant(1);
      }
      throw new EvalException("`arity' applied to non-function " + v);
    }

    /** first(p): returns the first element of non-empty list p. */
    public JamVal forFirstPrim() {
      JamCons c = confirmJamCons("first");
      return c.first();
    }

    /** rest(p): returns all but the first element of non-empty list p. */
    public JamVal forRestPrim() {
      JamCons c = confirmJamCons("rest");
      return c.rest();
    }

  }
}

class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

import junit.framework.TestCase;
import java.io.*;

/** Comprehensive tests for the Jam interpreter covering CBV, CBN, and CBNd evaluation. */
public class Assign2AgentTest extends TestCase {

  public Assign2AgentTest(String name) { super(name); }

  private void valueCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-value " + name, answer, interp.callByValue().toString());
  }

  private void nameCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-name " + name, answer, interp.callByName().toString());
  }

  private void needCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-need " + name, answer, interp.callByNeed().toString());
  }

  private void allCheck(String name, String answer, String program) {
    valueCheck(name, answer, program);
    nameCheck(name, answer, program);
    needCheck(name, answer, program);
  }

  // --- Constants ---

  public void testIntConstant() {
    allCheck("int", "0", "0");
    allCheck("negInt", "-5", "-5");
    allCheck("largeInt", "1000000", "1000000");
  }

  public void testBoolConstants() {
    allCheck("true", "true", "true");
    allCheck("false", "false", "false");
  }

  public void testEmptyConstant() {
    allCheck("empty", "()", "empty");
  }

  // --- Primitive functions as values ---

  public void testPrimFunValues() {
    allCheck("numberP", "number?", "number?");
    allCheck("functionP", "function?", "function?");
    allCheck("listP", "list?", "list?");
    allCheck("consP", "cons?", "cons?");
    allCheck("emptyP", "empty?", "empty?");
    allCheck("arity", "arity", "arity");
    allCheck("cons", "cons", "cons");
    allCheck("first", "first", "first");
    allCheck("rest", "rest", "rest");
  }

  // --- Arithmetic operations ---

  public void testArithmetic() {
    allCheck("add", "7", "3 + 4");
    allCheck("sub", "1", "5 - 4");
    allCheck("mul", "12", "3 * 4");
    allCheck("div", "3", "10 / 3");
    allCheck("negDiv", "-3", "-10 / 3");
    // Jam parser is left-associative with no operator precedence
    allCheck("leftAssoc", "20", "2 + 3 * 4");  // (2+3)*4
    allCheck("parens", "14", "2 + (3 * 4)");
  }

  // --- Unary operators ---

  public void testUnaryOps() {
    allCheck("unaryPlus", "5", "+5");
    allCheck("unaryMinus", "-5", "- 5");
    allCheck("tilde", "false", "~ true");
    allCheck("tildeF", "true", "~ false");
    allCheck("doubleNeg", "5", "- - 5");
  }

  // --- Comparison operators ---

  public void testComparisons() {
    allCheck("lt", "true", "3 < 5");
    allCheck("ltFalse", "false", "5 < 3");
    allCheck("gt", "true", "5 > 3");
    allCheck("gtFalse", "false", "3 > 5");
    allCheck("leq", "true", "3 <= 3");
    allCheck("leqLt", "true", "2 <= 3");
    allCheck("leqFalse", "false", "4 <= 3");
    allCheck("geq", "true", "3 >= 3");
    allCheck("geqGt", "true", "4 >= 3");
    allCheck("geqFalse", "false", "2 >= 3");
  }

  // --- Equality operators ---

  public void testEquality() {
    allCheck("intEq", "true", "5 = 5");
    allCheck("intNeq", "false", "5 = 6");
    allCheck("boolEq", "true", "true = true");
    allCheck("boolNeq", "false", "true = false");
    allCheck("emptyEq", "true", "empty = empty");
    allCheck("notEq", "true", "5 != 6");
    allCheck("notEqFalse", "false", "5 != 5");
  }

  // --- Short-circuit operators ---

  public void testShortCircuit() {
    allCheck("andTT", "true", "true & true");
    allCheck("andTF", "false", "true & false");
    allCheck("andFF", "false", "false & false");
    allCheck("andFT", "false", "false & true");
    allCheck("orTT", "true", "true | true");
    allCheck("orTF", "true", "true | false");
    allCheck("orFF", "false", "false | false");
    allCheck("orFT", "true", "false | true");
  }

  // --- If-then-else ---

  public void testIfThenElse() {
    allCheck("ifTrue", "1", "if true then 1 else 2");
    allCheck("ifFalse", "2", "if false then 1 else 2");
    allCheck("ifNested", "3", "if true then if false then 1 else 3 else 2");
  }

  // --- Map and application ---

  public void testMap() {
    allCheck("identity", "5", "(map x to x)(5)");
    allCheck("constant", "3", "(map x to 3)(99)");
    allCheck("add1", "6", "(map x to x + 1)(5)");
    allCheck("twoArgs", "7", "(map x,y to x + y)(3, 4)");
    allCheck("zeroArgs", "42", "(map to 42)()");
  }

  // --- Let ---

  public void testLet() {
    allCheck("letSimple", "5", "let x := 5; in x");
    allCheck("letCompute", "8", "let x := 3; y := 5; in x + y");
    allCheck("letNested", "10", "let x := 5; in let y := x + 5; in y");
    allCheck("letShadow", "3", "let x := 5; in let x := 3; in x");
  }

  // --- List operations ---

  public void testListOps() {
    allCheck("consOp", "(1)", "cons(1, empty)");
    allCheck("firstOp", "1", "first(cons(1, empty))");
    allCheck("restOp", "()", "rest(cons(1, empty))");
    allCheck("nestedCons", "(1 2 3)", "cons(1, cons(2, cons(3, empty)))");
    allCheck("firstNested", "1", "first(cons(1, cons(2, empty)))");
    allCheck("restNested", "(2)", "rest(cons(1, cons(2, empty)))");
  }

  // --- Predicate tests ---

  public void testPredicates() {
    allCheck("numberPTrue", "true", "number?(5)");
    allCheck("numberPFalse", "false", "number?(true)");
    allCheck("functionPTrue", "true", "function?(map x to x)");
    allCheck("functionPPrim", "true", "function?(cons?)");
    allCheck("functionPFalse", "false", "function?(5)");
    allCheck("listPEmpty", "true", "list?(empty)");
    allCheck("listPCons", "true", "list?(cons(1, empty))");
    allCheck("listPFalse", "false", "list?(5)");
    allCheck("consPTrue", "true", "cons?(cons(1, empty))");
    allCheck("consPEmpty", "false", "cons?(empty)");
    allCheck("consPFalse", "false", "cons?(5)");
    allCheck("emptyPTrue", "true", "empty?(empty)");
    allCheck("emptyPCons", "false", "empty?(cons(1, empty))");
    allCheck("emptyPFalse", "false", "empty?(5)");
  }

  // --- Arity ---

  public void testArity() {
    allCheck("arityMap1", "1", "arity(map x to x)");
    allCheck("arityMap2", "2", "arity(map x,y to x + y)");
    allCheck("arityMap0", "0", "arity(map to 42)");
    allCheck("arityPrimCons", "2", "arity(cons)");
    allCheck("arityPrimFirst", "1", "arity(first)");
    allCheck("arityPrimNumberP", "1", "arity(number?)");
  }

  // --- List equality ---

  public void testListEquality() {
    allCheck("listEq", "true", "cons(1, cons(2, empty)) = cons(1, cons(2, empty))");
    allCheck("listNeq", "false", "cons(1, cons(2, empty)) = cons(1, cons(3, empty))");
    allCheck("listLenNeq", "false", "cons(1, cons(2, empty)) = cons(1, empty)");
    allCheck("emptyEqEmpty", "true", "empty = empty");
  }

  // --- Closure equality ---

  public void testClosureEquality() {
    // Two distinct maps are NOT equal (identity comparison)
    allCheck("closureNeq", "false", "(map x to x) = (map x to x)");
    // Primitive functions are singletons, so they are equal to themselves
    allCheck("primEq", "true", "cons? = cons?");
    allCheck("primNeq", "false", "cons? = empty?");
    allCheck("primVsClosure", "false", "cons? = (map x to x)");
  }

  // --- CBV vs CBN vs CBNd closure equality ---

  public void testClosureEqualityCBV() {
    // In CBV, let m := (map x to x); m is evaluated once, so m = m is true
    valueCheck("cbvClosureEq", "true", "let m := map x to x; in m = m");
  }

  public void testClosureEqualityCBN() {
    // In CBN, let m := (map x to x); each use of m re-evaluates, creating distinct closures
    nameCheck("cbnClosureEq", "false", "let m := map x to x; in m = m");
  }

  public void testClosureEqualityCBNd() {
    // In CBNd, let m := (map x to x); first use evaluates and caches, so m = m is true
    needCheck("cbndClosureEq", "true", "let m := map x to x; in m = m");
  }

  // --- Short-circuit with side-effect-like divergence ---

  public void testShortCircuitCBN() {
    // In CBN, (true | x) should return true even though x is not defined
    // But & and | always evaluate their args... the short circuit prevents evaluating the second arg
    // Actually the short-circuit is in the BinOp visitor, not the evaluation policy
    allCheck("orShortCircuit", "true", "let x := 1; in true | false");
  }

  // --- Error cases ---

  public void testDivByZero() {
    try {
      allCheck("divByZero", "", "5 / 0");
      fail("Expected EvalException for division by zero");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testArityNonFunction() {
    try {
      allCheck("arityNonFun", "", "arity(5)");
      fail("Expected EvalException for arity of non-function");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testFirstEmpty() {
    try {
      allCheck("firstEmpty", "", "first(empty)");
      fail("Expected EvalException for first of empty");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testRestEmpty() {
    try {
      allCheck("restEmpty", "", "rest(empty)");
      fail("Expected EvalException for rest of empty");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testConsNonList() {
    try {
      allCheck("consNonList", "", "cons(1, 2)");
      fail("Expected EvalException for cons with non-list second arg");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testNonBoolIf() {
    try {
      allCheck("nonBoolIf", "", "if 5 then 1 else 2");
      fail("Expected EvalException for non-boolean if test");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testApplyNonFunction() {
    // 5(3) is a parse error (5 is a constant, not a factor), test via let instead
    try {
      allCheck("applyNonFun", "", "let f := 5; in f(3)");
      fail("Expected EvalException for applying non-function");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testWrongArity() {
    try {
      allCheck("wrongArity", "", "(map x to x)(1, 2)");
      fail("Expected EvalException for wrong arity");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testAddNonInteger() {
    try {
      allCheck("addNonInt", "", "true + 5");
      fail("Expected EvalException for adding non-integer");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testAndNonBool() {
    try {
      allCheck("andNonBool", "", "5 & true");
      fail("Expected EvalException for & with non-boolean");
    } catch (EvalException e) {
      // expected
    }
  }

  // --- Higher-order functions ---

  public void testHigherOrder() {
    allCheck("apply", "6",
      "let apply := map f,x to f(x); in apply(map x to x + 1, 5)");
    // Chained application needs parentheses in Jam: (compose(...))(3)
    allCheck("compose", "7",
      "let compose := map f,g to map x to f(g(x)); " +
      "in let c := compose(map x to x + 1, map x to x * 2); " +
      "in c(3)");
  }

  // --- Closures capturing environment ---

  public void testClosureCapture() {
    // Multi-binding let is like (map x,f to f(5))(10, map y to x+y) — x is NOT in scope when f's RHS is evaluated
    // Use nested let so that x is in scope when f is defined
    allCheck("capture", "15",
      "let x := 10; in let f := map y to x + y; in f(5)");
    allCheck("captureNested", "12",
      "let x := 3; in let f := map y to x * y; in f(4)");
  }

  // --- Y-combinator: CBV factorial ---

  public void testValueYFactorial() {
    String output = "720";
    String input = "let  Y := map f to let g := map x to f(map z to (x(x))(z)); in g(g);" +
      "  FACT := map f to map n to if n = 0 then 1 else n * f(n - 1);" +
      "in (Y(FACT))(6)";
    valueCheck("yfactorial", output, input);
  }

  // --- Y-combinator: CBN factorial ---

  public void testNameYFactorial() {
    String output = "720";
    String input = "let   Y := map f to let g := map x to f(x(x)); in g(g);" +
      "   FACT := map f to map n to if n = 0 then 1 else n * f(n - 1); in (Y(FACT))(6)";
    nameCheck("nameYFactorial", output, input);
  }

  // --- Y-combinator: CBNd factorial ---

  public void testNeedYFactorial() {
    String output = "720";
    String input = "let   Y := map f to let g := map x to f(x(x)); in g(g); " +
                   "   FACT := map f to map n to if n = 0 then 1 else n * f(n - 1); in (Y(FACT))(6)";
    needCheck("needYFactorial", output, input);
  }

  // --- Y-combinator: append ---

  public void testYAppend() {
    String output = "(1 2 3 1 2 3)";
    String input = "let    Y := map f to let g := map x to f(map z1,z2 to (x(x))(z1,z2)); in g(g);" +
                   "  APPEND := map ap to map x,y to if empty?(x) then y else cons(first(x), ap(rest(x), y));" +
                   "       l := cons(1,cons(2,cons(3,empty)));" +
                   "in (Y(APPEND))(l,l) ";
    allCheck("yappend", output, input);
  }

  // --- Y-combinator: fibonacci ---

  public void testFib() {
    String output = "((0 1) (1 1) (2 2) (3 3) (4 5) (5 8) (6 13) (7 21) (8 34) (9 55) (10 89))";
    String input =
      "let      Y := map f to let g := map x to f(x(x)); in g(g); " +
      "      pair := map x,y to cons(x, cons(y, empty));" +
      "   FIBHELP := map fibhelp to map k,fn,fnm1 to if k = 0 then fn else fibhelp(k - 1, fn + fnm1, fn); " +
      "in let FFIB := map ffib to map n to if n = 0 then 1 else (Y(FIBHELP))(n - 1,1,1); " +
      "   in let FIBS := map fibs to map k,l to " +
      "                    let fibk := (Y(FFIB))(k);" +
      "                    in if k >= 0 then fibs(k - 1, cons(pair(k,fibk), l)) else l; " +
      "      in (Y(FIBS))(10, empty)";
    needCheck("fib-need", output, input);
    nameCheck("fib-name", output, input);
  }

  // --- CBN laziness: unused argument not evaluated ---

  public void testCBNLazy() {
    // In CBN/CBNd, the second argument (1/0) is never evaluated because f ignores it
    nameCheck("lazyName", "5", "let f := map x,y to x; in f(5, 1/0)");
    needCheck("lazyNeed", "5", "let f := map x,y to x; in f(5, 1/0)");
  }

  public void testCBVStrict() {
    // In CBV, 1/0 is evaluated eagerly and causes an error
    try {
      valueCheck("strictValue", "", "let f := map x,y to x; in f(5, 1/0)");
      fail("Expected EvalException for CBV evaluating 1/0");
    } catch (EvalException e) {
      // expected
    }
  }

  // --- Currying ---

  public void testCurrying() {
    // Chained application needs intermediate let in Jam
    allCheck("curry", "7",
      "let add := map x to map y to x + y; in let add3 := add(3); in add3(4)");
  }

  // --- Nested let ---

  public void testNestedLet() {
    allCheck("nestedLet", "30",
      "let x := 5; in let y := 6; in x * y");
  }

  // --- If short-circuits: only one branch evaluated ---

  public void testIfLazy() {
    // The else branch has 1/0 which would error, but it's never evaluated
    allCheck("ifLazy", "1", "if true then 1 else 1/0");
    allCheck("ifLazy2", "2", "if false then 1/0 else 2");
  }

  // --- Mixed types in equality ---

  public void testMixedEquality() {
    allCheck("intVsBool", "false", "5 = true");
    allCheck("intVsEmpty", "false", "5 = empty");
    allCheck("listVsInt", "false", "cons(1, empty) = 1");
    allCheck("funVsInt", "false", "(map x to x) = 5");
  }
}

